# src/pieces.py

from enum import Enum, auto

class Color(Enum):
    BLACK = auto()
    WHITE = auto()

class Piece:
    def __init__(self, color):
        self.color = color

    def is_king(self):
        return False

class Pawn(Piece):
    def is_king(self):
        return False

class King(Piece):
    def is_king(self):
        return True
```

### Step 5: Implement `board.py`

```python
# src/board.py

from pieces import Color, Piece, Pawn, King
import numpy as np

class Board:
    def __init__(self):
        self.board = np.array([
            [None if i % 2 == j % 2 else Pawn(Color.BLACK) for j in range(8)] for i in range(8)
        ])
        self.board[3:5, :] = None
        self.current_player = Color.BLACK

    def print_board(self):
        from colorama import Fore, Style
        for row in self.board:
            line = ""
            for piece in row:
                if piece is None:
                    line += ". "
                elif isinstance(piece, Pawn):
                    if piece.color == Color.BLACK:
                        line += Fore.RED + "P " + Style.RESET_ALL
                    else:
                        line += Fore.BLUE + "p " + Style.RESET_ALL
                elif isinstance(piece, King):
                    if piece.color == Color.BLACK:
                        line += Fore.RED + "K " + Style.RESET_ALL
                    else:
                        line += Fore.BLUE + "k " + Style.RESET_ALL
            print(line)

    def move_piece(self, from_pos, to_pos):
        from_row, from_col = from_pos
        to_row, to_col = to_pos

        piece = self.board[from_row, from_col]
        if piece is None or piece.color != self.current_player:
            return False

        # Move the piece
        self.board[to_row, to_col] = piece
        self.board[from_row, from_col] = None

        # Check for capturing
        capture_directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for dr, dc in capture_directions:
            if to_row + dr >= 0 and to_row + dr < 8 and to_col + dc >= 0 and to_col + dc < 8:
                enemy_piece = self.board[to_row + dr, to_col + dc]
                target_square = self.board[to_row + 2 * dr, to_col + 2 * dc]
                if enemy_piece is not None and (enemy_piece.color != piece.color) and target_square is None:
                    # Capture the enemy piece
                    self.board[to_row + dr, to_col + dc] = None

        # King the pawn if it reaches the opposite end of the board
        if isinstance(piece, Pawn) and (self.current_player == Color.BLACK and to_row == 0 or self.current_player == Color.WHITE and to_row == 7):
            self.board[to_row, to_col] = King(self.current_player)

        # Switch players
        self.current_player = Color.WHITE if self.current_player == Color.BLACK else Color.BLACK

    def is_game_over(self):
        # TODO: Check for game over conditions (stalemate or checkmate)
        return False
```

### Step 6: Implement `checkers.py`

