# src/checkers.py

from board import Board

def get_user_input():
    return input("Enter move (e.g., e2-e4): ")

def is_valid_move(board, from_pos, to_pos):
    piece = board.board[from_pos[0], from_pos[1]]
    if piece is None:
        return False
    # Add your move validation logic here
    return True

def main():
    board = Board()
    while not board.is_game_over():
        board.print_board()
        user_input = get_user_input().split('-')
        from_pos = (int(user_input[0][1]) - 1, ord(user_input[0][0]) - ord('a'))
        to_pos = (int(user_input[1][1]) - 1, ord(user_input[1][0]) - ord('a'))
        if is_valid_move(board, from_pos, to_pos):
            board.move_piece(from_pos, to_pos)
        else:
            print("Invalid move. Try again.")
    board.print_board()
    print("Game Over")

if __name__ == "__main__":
    main()
```

